function findString (str) {<br />
 if (parseInt(navigator.appVersion)&lt;4) return;<br />
 var strFound;<br />
 if (window.find) {<br />
  // CODE FOR BROWSERS THAT SUPPORT window.find<br />
  strFound=self.find(str);<br />
  if (strFound){<br />
      console.log(&quot;found&quot;);<br />
      window.location = window.location;<br />
  }<br />
  if (!strFound) {<br />
   strFound=self.find(str,0,1);<br />
   while (self.find(str,0,1)) continue;<br />
  }<br />
 }<br />
}<br />
<br />
console.log(findString('busy'));
